import React from 'react';
import { Icon } from 'antd';
import styles from './LinkText.module.scss';

const LinkText = (props) => {
  const {
    site,
    git
  } = props
  return (
    <div className={styles.link}>
      <a href={site} target="_blank" rel="noopener noreferrer"><Icon type="home" style={{ fontSize: '2rem' }} /></a>
      <div />
      <a href={git} target="_blank" rel="noopener noreferrer"><Icon type="github" style={{ fontSize: '2rem' }} /></a>
    </div>
  );
};

export default LinkText;