import React from 'react';
import styles from './Intro.module.scss';

const recent = [
  "React",
  "Redux",
  "Redux-saga",
  "React-Context",
  "React-Hooks",
  "Node.js",
  "Immutable",
  "Immer",
  "Express",
  "Axios",
  "Sass",
  "Styled-Components",
  "MongoDb"
]
const prev = [
  "PHP",
  "jQuery",
  "RESTful API",
  "Ajax",
  "MySql",
  "MariaDb",
  "PostgreSql",
]
const Intro = (props) => {
  const {
    lang,
  } = props
  return (
    <div className={styles.intro}>
      <h2>Hello,</h2>
      <h2>I'm a <span>Front End Engineer</span> with using <span>React</span></h2>
      <div>{lang.recent}</div>
      <div>{recent.map((m, i) => <p key={i}>{m}</p>)}</div>
      <div>{lang.experienced}</div>
      <div>{prev.map((m, i) => <p key={i}>{m}</p>)}</div>
    </div>
  );
};

export default Intro;