import React from 'react';
import styles from './LanguageText.module.scss';

const LanguageText = (props) => {
  const {
    changeLanguage,
    current
  } = props
  return (
    <div className={styles.list}>
      <h1 className={current === 'kr' ? styles.langSelected : ''} onClick={() => { changeLanguage('kr') }}>KR</h1>
      <h1 className={current === 'en' ? styles.langSelected : ''} onClick={() => { changeLanguage('en') }}>EN</h1>
      <div className={styles.underbar} />
    </div>
  );
};

export default LanguageText;